module RefModule(input clk, input reset, input set, input d, output reg q, output reg qb);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset) begin
        q <= 0;
        qb <= 1;
    end else if (set) begin
        q <= 1;
        qb <= 0;
    end else begin
        q <= d;
        qb <= ~d;
    end
end

endmodule
